import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const y=JSON.parse('{"title":"玉渊潭公园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/yuyuantan.md","filePath":"parks/yuyuantan.md","lastUpdated":null}'),n={name:"parks/yuyuantan.md"};function d(i,t,o,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="玉渊潭公园" tabindex="-1">玉渊潭公园 <a class="header-anchor" href="#玉渊潭公园" aria-label="Permalink to &quot;玉渊潭公园&quot;">​</a></h1><blockquote><p>&quot;北京最大樱花观赏地，电视塔倒影如画。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>玉渊潭公园位于北京市海淀区，是北京最大的樱花观赏地，也是北京著名的城市公园。公园占地约137公顷，其中水面约60公顷，是北京三环内最大的公园。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-21:30（旺季），6:30-19:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">2元（樱花节期间10元）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春季樱花</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线/9号线军事博物馆站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市海淀区西三环中路10号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="辽金时期" tabindex="-1">辽金时期 <a class="header-anchor" href="#辽金时期" aria-label="Permalink to &quot;辽金时期&quot;">​</a></h3><p>玉渊潭地区在辽金时期就是著名的风景区，&quot;玉渊潭&quot;之名始见于金代。</p><h3 id="清代行宫" tabindex="-1">清代行宫 <a class="header-anchor" href="#清代行宫" aria-label="Permalink to &quot;清代行宫&quot;">​</a></h3><p>清代，乾隆皇帝在此修建行宫，是皇帝游幸之地。</p><h3 id="现代公园" tabindex="-1">现代公园 <a class="header-anchor" href="#现代公园" aria-label="Permalink to &quot;现代公园&quot;">​</a></h3><p>1960年，玉渊潭正式辟为公园，对外开放。</p><h2 id="园区布局" tabindex="-1">园区布局 <a class="header-anchor" href="#园区布局" aria-label="Permalink to &quot;园区布局&quot;">​</a></h2><p>玉渊潭公园分为东湖、西湖、南湖三个湖区。</p><h3 id="东湖" tabindex="-1">东湖 <a class="header-anchor" href="#东湖" aria-label="Permalink to &quot;东湖&quot;">​</a></h3><p>东湖是玉渊潭公园的主要景区，有樱花园、湿地园等。</p><h4 id="樱花园" tabindex="-1">樱花园 <a class="header-anchor" href="#樱花园" aria-label="Permalink to &quot;樱花园&quot;">​</a></h4><p>樱花园位于东湖湖畔，是北京最大的樱花园。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>面积</strong></td><td style="text-align:left;">约25公顷</td></tr><tr><td style="text-align:left;"><strong>樱花品种</strong></td><td style="text-align:left;">近30个品种</td></tr><tr><td style="text-align:left;"><strong>樱花数量</strong></td><td style="text-align:left;">近3000株</td></tr><tr><td style="text-align:left;"><strong>赏樱时间</strong></td><td style="text-align:left;">3月下旬至4月中旬</td></tr></tbody></table><h4 id="樱花品种" tabindex="-1">樱花品种 <a class="header-anchor" href="#樱花品种" aria-label="Permalink to &quot;樱花品种&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">品种</th><th style="text-align:center;">花色</th><th style="text-align:center;">花期</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>染井吉野</strong></td><td style="text-align:center;">淡粉色</td><td style="text-align:center;">3月下旬</td></tr><tr><td style="text-align:left;"><strong>关山</strong></td><td style="text-align:center;">粉红色</td><td style="text-align:center;">4月上旬</td></tr><tr><td style="text-align:left;"><strong>普贤象</strong></td><td style="text-align:center;">淡粉色</td><td style="text-align:center;">4月中旬</td></tr><tr><td style="text-align:left;"><strong>松月</strong></td><td style="text-align:center;">白色</td><td style="text-align:center;">4月中旬</td></tr><tr><td style="text-align:left;"><strong>大山樱</strong></td><td style="text-align:center;">深粉色</td><td style="text-align:center;">4月上旬</td></tr></tbody></table><h3 id="西湖" tabindex="-1">西湖 <a class="header-anchor" href="#西湖" aria-label="Permalink to &quot;西湖&quot;">​</a></h3><p>西湖有游船码头，可以划船游湖。</p><h3 id="南湖" tabindex="-1">南湖 <a class="header-anchor" href="#南湖" aria-label="Permalink to &quot;南湖&quot;">​</a></h3><p>南湖人较少，比较安静。</p><h2 id="樱花节" tabindex="-1">樱花节 <a class="header-anchor" href="#樱花节" aria-label="Permalink to &quot;樱花节&quot;">​</a></h2><p>玉渊潭公园每年春季举办樱花节，是北京著名的花事活动。</p><h3 id="举办时间" tabindex="-1">举办时间 <a class="header-anchor" href="#举办时间" aria-label="Permalink to &quot;举办时间&quot;">​</a></h3><p>每年3月下旬至4月中旬，根据花期调整。</p><h3 id="活动内容" tabindex="-1">活动内容 <a class="header-anchor" href="#活动内容" aria-label="Permalink to &quot;活动内容&quot;">​</a></h3><ul><li><strong>赏樱</strong>：观赏各种樱花</li><li><strong>摄影比赛</strong>：樱花摄影比赛</li><li><strong>文化活动</strong>：樱花文化展览</li><li><strong>美食</strong>：樱花主题美食</li></ul><h3 id="门票" tabindex="-1">门票 <a class="header-anchor" href="#门票" aria-label="Permalink to &quot;门票&quot;">​</a></h3><p>樱花节期间门票10元（平时2元）。</p><h2 id="电视塔倒影" tabindex="-1">电视塔倒影 <a class="header-anchor" href="#电视塔倒影" aria-label="Permalink to &quot;电视塔倒影&quot;">​</a></h2><p>玉渊潭公园的标志性景观是中央电视塔的倒影。</p><h3 id="最佳拍摄点" tabindex="-1">最佳拍摄点 <a class="header-anchor" href="#最佳拍摄点" aria-label="Permalink to &quot;最佳拍摄点&quot;">​</a></h3><ul><li><strong>东湖湖畔</strong>：可以拍到电视塔在湖中的倒影</li><li><strong>傍晚时分</strong>：夕阳西下，景色最美</li></ul><h3 id="拍摄建议" tabindex="-1">拍摄建议 <a class="header-anchor" href="#拍摄建议" aria-label="Permalink to &quot;拍摄建议&quot;">​</a></h3><p>天气晴好时，湖面平静，倒影清晰，是拍摄的最佳时机。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约2-3小时）</strong>：</p><p>南门 → 东湖樱花园 → 西湖游船 → 电视塔倒影 → 北门</p><p><strong>樱花节路线</strong>：</p><p>西门 → 樱花园（赏樱） → 东湖湖畔 → 南门</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">1号线/9号线军事博物馆站A口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">1路、32路、65路等玉渊潭南门站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从军事博物馆步行约10分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>樱花最佳时间</strong>：3月下旬至4月中旬</li><li><strong>避开人流</strong>：早上7:00前或下午4:00后人较少</li><li><strong>樱花节门票</strong>：樱花节期间门票10元</li><li><strong>划船体验</strong>：可以划船游湖</li><li><strong>拍照建议</strong>：下午3:00-5:00光线最佳</li><li><strong>结合游览</strong>：可与军事博物馆、首博一起游览</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">军事博物馆</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">国家级军事博物馆</td></tr><tr><td style="text-align:left;">首都博物馆</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">北京历史文化</td></tr><tr><td style="text-align:left;">中华世纪坛</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">文化建筑</td></tr><tr><td style="text-align:left;">中央电视塔</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">俯瞰北京</td></tr></tbody></table><hr><p><strong>📍 地址</strong>：北京市海淀区西三环中路10号 <strong>📞 电话</strong>：010-88653800</p>',54)])])}const c=e(n,[["render",d]]);export{y as __pageData,c as default};
